export interface AdMetric {
  id: string;
  name: string;
  creative_type: string;
  platform: string;
  audience: string;
  spend: number;
  revenue: number;
  roi: number;
  ctr: number;
  impressions: number;
  clicks: number;
  reason?: string; // AI's reasoning for selection
}

export interface AnalysisResult {
  top_ads: AdMetric[];
  low_ads: AdMetric[];
  patterns: string[];
  performance_summary: string;
}

export interface CsvRow {
  [key: string]: string | number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

export const analyzeAdsData = async (csvData: string): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    You are an expert advertising data analyst and hedge fund algorithm.
    Analyze the following ad performance data in CSV format.

    Data:
    ${csvData}

    Your job:
    1. Detect top performing ads based on ROI (Revenue/Spend) and High CTR.
    2. Detect underperforming ads (Low ROI, High Spend/Low Return).
    3. Identify patterns across creative_type, audience, and platform.
    4. Summarize overall performance trends with a professional, financial tone.

    Ensure 'spend', 'revenue', 'roi', 'ctr', 'impressions', and 'clicks' are numbers in the output. Calculate ROI if not present (Revenue - Spend) / Spend * 100, or simple ROAS Revenue / Spend. Let's use ROAS (Return on Ad Spend) as the ROI metric for simplicity in display, or typically (Revenue - Spend) / Spend. Let's stick to ROAS: Revenue / Spend. If Revenue is 4200 and Spend is 1500, ROAS is 2.8.

    Provide a 'reason' field for why an ad is in the top or low list.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          top_ads: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                creative_type: { type: Type.STRING },
                platform: { type: Type.STRING },
                audience: { type: Type.STRING },
                spend: { type: Type.NUMBER },
                revenue: { type: Type.NUMBER },
                roi: { type: Type.NUMBER, description: "ROAS (Revenue / Spend)" },
                ctr: { type: Type.NUMBER, description: "Click Through Rate in percentage" },
                impressions: { type: Type.NUMBER },
                clicks: { type: Type.NUMBER },
                reason: { type: Type.STRING, description: "Why this ad is top performing" }
              },
              required: ["id", "name", "spend", "revenue", "roi", "reason"]
            }
          },
          low_ads: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                creative_type: { type: Type.STRING },
                platform: { type: Type.STRING },
                audience: { type: Type.STRING },
                spend: { type: Type.NUMBER },
                revenue: { type: Type.NUMBER },
                roi: { type: Type.NUMBER },
                ctr: { type: Type.NUMBER },
                impressions: { type: Type.NUMBER },
                clicks: { type: Type.NUMBER },
                reason: { type: Type.STRING, description: "Why this ad is underperforming" }
              },
              required: ["id", "name", "spend", "revenue", "roi", "reason"]
            }
          },
          patterns: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of identified patterns and insights"
          },
          performance_summary: {
            type: Type.STRING,
            description: "Executive summary of the analysis"
          }
        },
        required: ["top_ads", "low_ads", "patterns", "performance_summary"]
      }
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI");
  }

  return JSON.parse(text) as AnalysisResult;
};

import React, { useRef, useState } from 'react';
import { Upload, FileText, Loader2, AlertCircle } from 'lucide-react';

interface FileUploadProps {
  onFileUpload: (content: string) => void;
  isLoading: boolean;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileUpload, isLoading }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setError(null);
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== "text/csv" && !file.name.endsWith(".csv")) {
      setError("Please upload a valid CSV file.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      const content = e.target?.result as string;
      onFileUpload(content);
    };
    reader.onerror = () => setError("Failed to read file.");
    reader.readAsText(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setError(null);
    const file = e.dataTransfer.files?.[0];
    if (!file) return;

    if (file.type !== "text/csv" && !file.name.endsWith(".csv")) {
      setError("Please upload a valid CSV file.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      const content = e.target?.result as string;
      onFileUpload(content);
    };
    reader.readAsText(file);
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div
        className={`relative group border-2 border-dashed rounded-xl p-12 transition-all duration-300 ease-in-out
          ${isLoading ? 'border-indigo-500/50 bg-indigo-500/5' : 'border-slate-700 hover:border-indigo-400 hover:bg-slate-800/50 bg-slate-900/50'}
        `}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
      >
        <input
          type="file"
          ref={fileInputRef}
          onChange={handleFileChange}
          className="hidden"
          accept=".csv"
        />

        <div className="flex flex-col items-center justify-center text-center space-y-4">
          <div className={`p-4 rounded-full ${isLoading ? 'bg-indigo-500/10' : 'bg-slate-800 group-hover:bg-indigo-500/20'} transition-colors duration-300`}>
            {isLoading ? (
              <Loader2 className="w-8 h-8 text-indigo-400 animate-spin" />
            ) : (
              <Upload className="w-8 h-8 text-indigo-400" />
            )}
          </div>

          <div className="space-y-2">
            <h3 className="text-lg font-medium text-slate-200">
              {isLoading ? 'Analyzing Data...' : 'Upload Ad Performance CSV'}
            </h3>
            <p className="text-sm text-slate-400 max-w-sm">
              Drag and drop your CSV file here, or click to browse.
              Our AI algorithm will allocate budget and detect patterns instantly.
            </p>
          </div>

          {!isLoading && (
            <button
              onClick={() => fileInputRef.current?.click()}
              className="px-6 py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white text-sm font-medium rounded-lg transition-all shadow-lg shadow-indigo-500/20"
            >
              Select File
            </button>
          )}
        </div>

        {error && (
          <div className="absolute -bottom-16 left-0 right-0 flex items-center justify-center text-rose-400 text-sm bg-rose-950/30 py-2 rounded-lg border border-rose-900/50">
            <AlertCircle className="w-4 h-4 mr-2" />
            {error}
          </div>
        )}
      </div>
    </div>
  );
};

export default FileUpload;

