import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

export const analyzeAdsData = async (csvData: string): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    You are a Senior Quantitative Analyst at a top-tier Ad-Tech Hedge Fund.
    Analyze the following ad performance dataset (CSV) to allocate capital efficiently.

    Data Payload:
    ${csvData}

    Objectives:
    1. Identify "Alpha Generators" (Top Assets): High ROAS, Scalable CTR.
    2. Identify "Liabilities" (Underperformers): Cash burn, low return.
    3. Pattern Recognition: Correlate creative_type, audience, and platform (Exchange) to performance.
    4. Executive Memo: Write a concise, high-level financial summary.
    5. Action Protocol:
       - SCALE: Specific creatives/platforms to increase budget.
       - PAUSE: Specific underperformers to cut.
       - TEST: New creative angles or audiences to hedge risk.
       - ALLOCATION: A single powerful sentence on where to move money (e.g., "Shift 15% from FB to TikTok").

    Output constraints:
    - Ensure 'roi' is calculated as Revenue / Spend (ROAS).
    - Provide a concise 'reason' for each asset's classification.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          top_ads: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                creative_type: { type: Type.STRING },
                platform: { type: Type.STRING },
                audience: { type: Type.STRING },
                spend: { type: Type.NUMBER },
                revenue: { type: Type.NUMBER },
                roi: { type: Type.NUMBER, description: "ROAS (Revenue / Spend)" },
                ctr: { type: Type.NUMBER, description: "Click Through Rate in percentage" },
                impressions: { type: Type.NUMBER },
                clicks: { type: Type.NUMBER },
                reason: { type: Type.STRING, description: "Analyst note on why this is a buy" }
              },
              required: ["id", "name", "spend", "revenue", "roi", "reason"]
            }
          },
          low_ads: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                creative_type: { type: Type.STRING },
                platform: { type: Type.STRING },
                audience: { type: Type.STRING },
                spend: { type: Type.NUMBER },
                revenue: { type: Type.NUMBER },
                roi: { type: Type.NUMBER },
                ctr: { type: Type.NUMBER },
                impressions: { type: Type.NUMBER },
                clicks: { type: Type.NUMBER },
                reason: { type: Type.STRING, description: "Analyst note on why this is a sell" }
              },
              required: ["id", "name", "spend", "revenue", "roi", "reason"]
            }
          },
          patterns: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of identified market patterns"
          },
          performance_summary: {
            type: Type.STRING,
            description: "Executive summary for the portfolio manager"
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              scale_actions: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "Specific actions to scale profitable ads"
              },
              pause_actions: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "Specific actions to pause losing ads"
              },
              test_ideas: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "Hypotheses for new creative tests"
              },
              budget_shift_tip: {
                type: Type.STRING,
                description: "One sentence summary of budget reallocation"
              }
            },
            required: ["scale_actions", "pause_actions", "test_ideas", "budget_shift_tip"]
          }
        },
        required: ["top_ads", "low_ads", "patterns", "performance_summary", "recommendations"]
      }
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI");
  }

  return JSON.parse(text) as AnalysisResult;
};

