interface RealTimeAllocatorProps {
  onBack: () => void;
}

const RealTimeAllocator: React.FC<RealTimeAllocatorProps> = ({ onBack }) => {
  const [status, setStatus] = useState<'idle' | 'connecting' | 'fetching' | 'analyzing' | 'complete'>('idle');
  const [logs, setLogs] = useState<string[]>([]);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [loadingStep, setLoadingStep] = useState(0);

  const addLog = (msg: string) => setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);

  const generateMockLiveData = () => {
    // Generates a randomized CSV payload to simulate live data fetch
    const campaigns = [
      { name: 'Retargeting_Q3_Dyn', type: 'Dynamic', platform: 'Facebook', aud: 'Cart_Abandoners' },
      { name: 'TopFunnel_Lookalike_1%', type: 'Video', platform: 'Instagram', aud: 'Broad_LAL' },
      { name: 'Story_Promo_Flash', type: 'Story', platform: 'Instagram', aud: 'Followers' },
      { name: 'Reels_Viral_Hook_A', type: 'Reel', platform: 'Facebook', aud: 'GenZ_Interest' },
      { name: 'Search_Brand_Defense', type: 'Search', platform: 'Google', aud: 'High_Intent' },
      { name: 'Display_Remarketing', type: 'Image', platform: 'AudienceNetwork', aud: 'Site_Visitors' },
    ];

    let csv = `ad_id,ad_name,creative_type,platform,audience,spend,revenue,impressions,clicks\n`;

    campaigns.forEach((c, i) => {
      const spend = Math.floor(Math.random() * 5000) + 500;
      // Randomize ROAS between 0.5 and 4.0
      const roas = (Math.random() * 3.5) + 0.5; 
      const revenue = Math.floor(spend * roas);
      const impressions = Math.floor(spend * (Math.random() * 20 + 10));
      const clicks = Math.floor(impressions * (Math.random() * 0.03 + 0.01));

      csv += `LIVE_${100+i},${c.name},${c.type},${c.platform},${c.aud},${spend},${revenue},${impressions},${clicks}\n`;
    });

    return csv;
  };

  const handleConnect = async () => {
    setStatus('connecting');
    setLogs([]);
    setLoadingStep(0);

    // Simulate connection sequence
    addLog("Initiating OAuth 2.0 handshake with Meta Graph API...");
    await new Promise(r => setTimeout(r, 1200));
    setLoadingStep(1);
    addLog("Token verified. Access granted to Ad Account: ID_8829301...");

    setStatus('fetching');
    await new Promise(r => setTimeout(r, 1000));
    setLoadingStep(2);
    addLog("Streaming last 24h campaign performance data...");
    addLog("Ingesting 14 active campaign shards...");

    setStatus('analyzing');
    await new Promise(r => setTimeout(r, 800));
    setLoadingStep(3);
    addLog("Sending payload to PreThink AI Optimization Engine...");

    try {
      const liveCsv = generateMockLiveData();
      const result = await analyzeAdsData(liveCsv);
      setData(result);
      setStatus('complete');
      addLog("Optimization Complete.");
    } catch (e) {
      addLog("ERROR: Engine failure.");
      setStatus('idle');
    }
  };

  if (status === 'complete' && data) {
    return (
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="flex items-center justify-between mb-6 bg-emerald-950/20 border border-emerald-900/50 p-3 rounded-sm">
          <div className="flex items-center gap-3">
            <span className="relative flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-emerald-500"></span>
            </span>
            <span className="text-xs font-mono text-emerald-400 uppercase tracking-widest">
              Live Connection Active // Auto-Refresh: 5m
            </span>
          </div>
          <button 
            onClick={() => setStatus('idle')}
            className="text-xs font-mono text-zinc-500 hover:text-white uppercase"
          >
            Disconnect
          </button>
        </div>
        <Dashboard data={data} onReset={handleConnect} />
      </div>
    );
  }

  return (
    <div className="min-h-[60vh] flex flex-col items-center justify-center max-w-2xl mx-auto">

      {/* HEADER */}
      <div className="text-center mb-10 space-y-4">
        <div className="inline-flex items-center justify-center p-4 bg-zinc-900 rounded-full border border-zinc-800 mb-4">
          <Globe className={`w-8 h-8 ${status === 'idle' ? 'text-zinc-500' : 'text-emerald-500 animate-pulse'}`} />
        </div>
        <h2 className="text-2xl font-mono text-white tracking-tight">Real-Time Capital Allocator</h2>
        <p className="text-zinc-500 font-mono text-xs uppercase tracking-widest">
          Connect directly to ad exchanges for instant arbitrage.
        </p>
      </div>

      {/* CONNECT CARD */}
      <div className="w-full bg-zinc-900/50 border border-zinc-800 rounded-sm overflow-hidden backdrop-blur-sm">

        {/* Connection Status Bar */}
        <div className="bg-zinc-950 border-b border-zinc-800 p-4 flex justify-between items-center">
          <div className="flex items-center gap-2 text-xs font-mono text-zinc-400">
            <Server className="w-4 h-4" />
            <span>META_GRAPH_API_V18.0</span>
          </div>
          <div className="flex items-center gap-2">
            {status === 'idle' ? (
              <span className="flex items-center gap-1.5 text-[10px] text-zinc-600 bg-zinc-900 px-2 py-1 rounded-sm border border-zinc-800">
