            ) : (
              <span className="flex items-center gap-1.5 text-[10px] text-emerald-500 bg-emerald-950/30 px-2 py-1 rounded-sm border border-emerald-900/30">
                <Loader2 className="w-3 h-3 animate-spin" />
                {status.toUpperCase()}
              </span>
            )}
          </div>
        </div>

        <div className="p-8 flex flex-col items-center">

          {status === 'idle' ? (
