const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }
  return new GoogleGenAI({ apiKey });
}

export const analyzeAdsData = async (csvData: string): Promise<AnalysisResult> => {
  const ai = getAiClient();

  const prompt = `
    You are an AI optimization engine and Senior Quantitative Analyst.

    Task: Analyze the ad performance dataset (CSV) and generate actionable trading algorithms.

    Data Payload:
    ${csvData}

    REQUIRED OUTPUTS:
    1. MARKET ANALYSIS:
       - Detect "Alpha Generators" (Top Assets): High ROAS, Scalable.
       - Detect "Liabilities" (Underperformers): Cash burn, low return.
       - Identify Patterns: Correlations in creative_type, audience, platform.
       - Executive Memo: Concise financial summary.

    2. OPTIMIZATION PROTOCOL (The "Engine" Output):
       - scale_actions: Specific instruction on what to scale (e.g. "Scale AD_004 on TikTok by 20%").
       - pause_actions: Specific instruction on what to kill (e.g. "Immediate pause on AD_002 due to 0.8x ROAS").
       - test_ideas: Hypothesis for new alpha (e.g. "Test Video format for Parents audience").
       - budget_shift_tip: High-impact allocation move (e.g. "Reallocate 15% from FB to YouTube").

    Constraints:
    - 'roi' must be Revenue / Spend.
    - Maintain a strict, high-frequency trading algorithm persona.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          top_ads: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                creative_type: { type: Type.STRING },
                platform: { type: Type.STRING },
                audience: { type: Type.STRING },
                spend: { type: Type.NUMBER },
                revenue: { type: Type.NUMBER },
                roi: { type: Type.NUMBER, description: "ROAS (Revenue / Spend)" },
                ctr: { type: Type.NUMBER, description: "Click Through Rate in percentage" },
                impressions: { type: Type.NUMBER },
                clicks: { type: Type.NUMBER },
                reason: { type: Type.STRING, description: "Analyst note on why this is a buy" }
              },
              required: ["id", "name", "spend", "revenue", "roi", "reason"]
            }
          },
          low_ads: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                creative_type: { type: Type.STRING },
                platform: { type: Type.STRING },
                audience: { type: Type.STRING },
                spend: { type: Type.NUMBER },
                revenue: { type: Type.NUMBER },
                roi: { type: Type.NUMBER },
                ctr: { type: Type.NUMBER },
                impressions: { type: Type.NUMBER },
                clicks: { type: Type.NUMBER },
                reason: { type: Type.STRING, description: "Analyst note on why this is a sell" }
              },
              required: ["id", "name", "spend", "revenue", "roi", "reason"]
            }
          },
          patterns: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of identified market patterns"
          },
          performance_summary: {
            type: Type.STRING,
            description: "Executive summary for the portfolio manager"
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              scale_actions: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "Actionable scaling commands"
              },
              pause_actions: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "Actionable pause commands"
              },
              test_ideas: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "New alpha generation ideas"
              },
              budget_shift_tip: {
                type: Type.STRING,
                description: "Capital reallocation instruction"
              }
            },
            required: ["scale_actions", "pause_actions", "test_ideas", "budget_shift_tip"]
          }
        },
        required: ["top_ads", "low_ads", "patterns", "performance_summary", "recommendations"]
      }
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI");
  }

  return JSON.parse(text) as AnalysisResult;
};

export const analyzeCompetitors = async (myCompany: string, competitors: string, industry: string): Promise<CompetitorAnalysisResult> => {
  const ai = getAiClient();

  const prompt = `
    You are a Director of Corporate Strategy and Market Intelligence.

    Target Company: ${myCompany}
    Competitor List: ${competitors}
    Industry / Vertical: ${industry}

    Task: Perform a deep-dive competitive analysis. 
    1. Estimate market share and brand sentiment based on general knowledge of these types of companies in this industry (simulate realistic data if specific private data is unknown).
    2. Perform a SWOT analysis specifically for ${myCompany} in the context of these competitors.
    3. Identify "Attack Vectors" - aggressive strategies to capture market share from these specific competitors.

    Output Constraints:
    - 'market_share_est' should be a percentage (0-100). Ensure total is around 100% (including 'Others').
    - 'brand_sentiment' and 'ad_intensity' are 0-100 scores.
    - Be concise, strategic, and ruthless in "attack_vectors".
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          market_landscape: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                market_share_est: { type: Type.NUMBER },
                brand_sentiment: { type: Type.NUMBER },
                ad_intensity: { type: Type.NUMBER },
                main_strategy: { type: Type.STRING }
              },
              required: ["name", "market_share_est", "brand_sentiment", "ad_intensity", "main_strategy"]
            }
          },
          swot: {
            type: Type.OBJECT,
            properties: {
              strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
              weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
              opportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
              threats: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["strengths", "weaknesses", "opportunities", "threats"]
          },
          key_insights: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          attack_vectors: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["market_landscape", "swot", "key_insights", "attack_vectors"]
      }
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI");
  }

  return JSON.parse(text) as CompetitorAnalysisResult;
};

