// Define types for the FB SDK
declare global {
  interface Window {
    FB: any;
    fbAsyncInit: () => void;
  }
}

const APP_ID = 'YOUR_META_APP_ID'; // REPLACE THIS WITH YOUR ACTUAL FACEBOOK APP ID
const API_VERSION = 'v18.0';

export interface MetaAdAccount {
  id: string;
  name: string;
  account_id: string;
  currency: string;
}

export const initFacebookSdk = (): Promise<void> => {
  return new Promise((resolve) => {
    if (window.FB) {
      resolve();
      return;
    }

    window.fbAsyncInit = function() {
      window.FB.init({
        appId      : APP_ID,
        cookie     : true,
        xfbml      : true,
        version    : API_VERSION
      });
      resolve();
    };
  });
};

export const loginToFacebook = (): Promise<string> => {
  return new Promise((resolve, reject) => {
    if (!window.FB) return reject("FB SDK not loaded");

    window.FB.login((response: any) => {
      if (response.authResponse) {
        resolve(response.authResponse.accessToken);
      } else {
        reject("User cancelled login or did not fully authorize.");
      }
    }, { scope: 'ads_read,read_insights' }); // Permissions required
  });
};

export const getAdAccounts = async (accessToken: string): Promise<MetaAdAccount[]> => {
  const url = `https://graph.facebook.com/${API_VERSION}/me/adaccounts?fields=name,account_id,currency&access_token=${accessToken}`;
  const response = await fetch(url);
  const data = await response.json();
  if (data.error) throw new Error(data.error.message);
  return data.data;
};

export const getAccountInsights = async (accountId: string, accessToken: string): Promise<string> => {
  // Fetch campaigns with insights
  const fields = 'campaign_name,impressions,clicks,spend,cpc,ctr,actions,action_values';
  const url = `https://graph.facebook.com/${API_VERSION}/${accountId}/insights?level=campaign&date_preset=maximum&fields=${fields}&access_token=${accessToken}`;

  const response = await fetch(url);
  const json = await response.json();

  if (json.error) throw new Error(json.error.message);

  // Convert Graph API JSON to the CSV string format our Gemini Service expects
  // CSV Header: ad_name,platform,impressions,clicks,ctr,spend,conversions,roas,creative_type,audience

  let csvContent = `ad_name,platform,impressions,clicks,ctr,spend,conversions,roas,creative_type,audience\n`;

  json.data.forEach((row: any) => {
    // Extract Purchase value for ROAS calculation
    let purchaseValue = 0;
    let conversions = 0;

    if (row.action_values) {
      const purchaseAction = row.action_values.find((a: any) => a.action_type === 'purchase');
      if (purchaseAction) purchaseValue = parseFloat(purchaseAction.value);
    }

    if (row.actions) {
      const purchaseCount = row.actions.find((a: any) => a.action_type === 'purchase');
      if (purchaseCount) conversions = parseInt(purchaseCount.value);
    }

    const spend = parseFloat(row.spend) || 0;
    const roas = spend > 0 ? (purchaseValue / spend).toFixed(2) : 0;
    const ctr = row.ctr ? (parseFloat(row.ctr) * 100).toFixed(2) : 0; // API returns decimal, we want percentage sometimes, but consistent with demo data

    // Infer creative/audience as they aren't in high-level insights easily without extra calls
    const creativeType = 'mixed'; 
    const audience = 'meta_custom_audience';

    csvContent += `${row.campaign_name.replace(/,/g, '')},Meta,${row.impressions},${row.clicks},${ctr},${spend},${conversions},${roas},${creativeType},${audience}\n`;
  });

  return csvContent;
};

import React, { useState, useEffect } from 'react';
import { AnalysisResult } from '../types';
import { analyzeAdsData } from '../services/geminiService';
import { initFacebookSdk, loginToFacebook, getAdAccounts, getAccountInsights, MetaAdAccount } from '../services/metaService';
import Dashboard from './Dashboard';
