  // --- RENDER COMPLETE DASHBOARD (SPLIT VIEW) ---

  if (status === 'complete' && data) {
    return (
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 h-[calc(100vh-100px)] flex flex-col">

        {/* Top Status Bar */}
