  }
  return new GoogleGenAI({ apiKey });
}

// Helper for rate limit retries
const retryOperation = async <T>(
  operation: () => Promise<T>, 
  maxRetries: number = 3, 
  baseDelay: number = 4000
): Promise<T> => {
  let lastError: any;

  for (let i = 0; i < maxRetries; i++) {
    try {
      return await operation();
    } catch (error: any) {
      lastError = error;

      const isRateLimit = 
        error?.status === 429 || 
        error?.code === 429 ||
        error?.message?.includes('429') || 
        error?.message?.includes('Quota exceeded') ||
        error?.message?.includes('RESOURCE_EXHAUSTED');

      if (!isRateLimit) {
        throw error;
      }

      if (i === maxRetries - 1) break;

      // Extract retry delay from error if available (e.g. "Please retry in 7.46s")
      let delay = baseDelay * Math.pow(2, i);
      const match = error?.message?.match(/retry in (\d+(\.\d+)?)s/);
      if (match && match[1]) {
         delay = Math.ceil(parseFloat(match[1]) * 1000) + 1000; // Add 1s buffer
      }

      console.warn(`Gemini API Rate limit hit. Retrying in ${delay}ms...`);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }

  throw lastError;
};

