import React, { useRef, useState } from 'react';
import { Upload, FileCode, AlertTriangle, ShieldCheck } from 'lucide-react';

interface FileUploadProps {
  onFileUpload: (content: string) => void;
  isLoading: boolean;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileUpload, isLoading }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setError(null);
    const file = event.target.files?.[0];
    if (!file) return;
    processFile(file);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setError(null);
    const file = e.dataTransfer.files?.[0];
    if (!file) return;
    processFile(file);
  };

  const processFile = (file: File) => {
    if (file.type !== "text/csv" && !file.name.endsWith(".csv")) {
      setError("INVALID FORMAT. CSV REQUIRED.");
      return;
    }
    const reader = new FileReader();
    reader.onload = (e) => onFileUpload(e.target?.result as string);
    reader.readAsText(file);
  };

  return (
    <div className="w-full">
      <div
        className={`relative group h-64 border-2 border-dashed transition-all duration-300 ease-out flex flex-col items-center justify-center cursor-pointer
          ${isLoading ? 'border-brand-volt bg-brand-volt/5' : 'border-zinc-800 hover:border-white bg-zinc-900/50 hover:bg-zinc-900'}
        `}
        onDragOver={(e) => e.preventDefault()}
        onDrop={handleDrop}
        onClick={() => !isLoading && fileInputRef.current?.click()}
      >
        <input
          type="file"
          ref={fileInputRef}
          onChange={handleFileChange}
          className="hidden"
          accept=".csv"
        />

        <div className="space-y-4 text-center">
            {isLoading ? (
               <div className="flex flex-col items-center gap-4">
                  <div className="w-8 h-8 border-t-2 border-brand-volt rounded-full animate-spin"></div>
                  <span className="label-mono text-brand-volt text-xs">Analyzing Vectors...</span>
               </div>
            ) : (
               <>
                 <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-2">
                    <Upload className="w-5 h-5 text-black" />
                 </div>
                 <div>
                    <h3 className="nike-header text-xl text-white">Upload Ledger</h3>
                    <p className="text-zinc-500 text-sm mt-1">Drag & Drop CSV or Click</p>
                 </div>
               </>
            )}
        </div>

        {error && (
          <div className="absolute bottom-4 text-red-500 text-xs font-mono bg-red-950/20 px-3 py-1 rounded">
            {error}
          </div>
        )}
      </div>

      <div className="mt-4 flex justify-center text-[10px] font-mono text-zinc-600 uppercase tracking-widest">
        <span className="flex items-center gap-2"><ShieldCheck className="w-3 h-3" /> End-to-End Encrypted</span>
      </div>
    </div>
  );
};

export default FileUpload;

