import React, { useState, useRef } from 'react';
import { analyzeBudgetAndCreative, generateCreativeFromPrompt } from '../services/geminiService';
import { BudgetAnalysisResult, GeneratedCreative } from '../types';
import { DEMO_BUDGET_DATA } from '../constants';
import { 
  ArrowLeft, FileSpreadsheet, Activity, AlertTriangle, 
  Wand2, Zap, ArrowRight, ImagePlus,
  Loader2, Scale,
} from 'lucide-react';

interface BudgetAllocatorProps {
  onBack: () => void;
}

const BudgetAllocator: React.FC<BudgetAllocatorProps> = ({ onBack }) => {
  const [step, setStep] = useState<'input' | 'analyzing' | 'dashboard'>('input');
  const [data, setData] = useState<BudgetAnalysisResult | null>(null);

  // Image Gen State
  const [productImage, setProductImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedAd, setGeneratedAd] = useState<GeneratedCreative | null>(null);
  const [genError, setGenError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null); 
  const csvInputRef = useRef<HTMLInputElement>(null); 

  const handleDemoLoad = async () => {
    setStep('analyzing');
    try {
      const result = await analyzeBudgetAndCreative(DEMO_BUDGET_DATA);
      setData(result);
      setStep('dashboard');
    } catch (e) {
      console.error(e);
      setStep('input');
      alert("Analysis failed.");
    }
  };

  const handleCsvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setStep('analyzing');
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const content = event.target?.result as string;
        if (!content) throw new Error("File is empty");
        const result = await analyzeBudgetAndCreative(content);
        setData(result);
        setStep('dashboard');
      } catch (err) {
        console.error(err);
        setStep('input');
        alert("Failed to analyze CSV.");
      }
    };
    reader.readAsText(file);
  };

  const handleProductUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setProductImage(reader.result as string);
        setGenError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!productImage || !data) return;
    setIsGenerating(true);
    setGenError(null);
    try {
      const cleanBase64 = productImage.split(',')[1];
      const result = await generateCreativeFromPrompt(cleanBase64, data.gemini_generation_prompt);
      setGeneratedAd(result);
    } catch (e: any) {
      console.error(e);
      setGenError("Generation failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  if (step === 'input') {
    return (
      <div className="max-w-4xl mx-auto animate-fade-up">

        <div className="mb-10">
           <button onClick={onBack} className="group flex items-center gap-2 text-[10px] font-mono text-zinc-500 hover:text-white uppercase tracking-widest mb-4">
             <ArrowLeft className="w-3 h-3 group-hover:-translate-x-1 transition-transform" />
             Return
           </button>
           <h2 className="nike-header text-6xl text-white leading-none">
             Live<span className="text-zinc-700">Allocator</span>
           </h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
           {/* Option 1: Upload */}
           <div 
             onClick={() => csvInputRef.current?.click()}
             className="group relative bg-zinc-900 hover:bg-brand-volt transition-colors duration-300 h-[300px] border border-zinc-800 p-8 flex flex-col justify-between cursor-pointer overflow-hidden"
           >
              <input type="file" ref={csvInputRef} onChange={handleCsvUpload} className="hidden" accept=".csv" />
              <div className="flex justify-between items-start">
                 <FileSpreadsheet className="w-8 h-8 text-zinc-500 group-hover:text-black transition-colors" />
                 <ArrowRight className="w-6 h-6 text-zinc-700 group-hover:text-black -rotate-45 group-hover:rotate-0 transition-all duration-500" />
              </div>
              <div className="relative z-10">
                 <h3 className="nike-header text-3xl text-white group-hover:text-black mb-2 transition-colors">Ingest<br/>Stream</h3>
                 <p className="label-mono text-[10px] text-zinc-500 group-hover:text-black/70">Upload Live CSV Data</p>
              </div>
           </div>

           {/* Option 2: Demo */}
           <div 
             onClick={handleDemoLoad}
             className="group relative bg-white hover:bg-zinc-200 transition-colors duration-300 h-[300px] border border-white p-8 flex flex-col justify-between cursor-pointer"
           >
              <div className="flex justify-between items-start">
                 <Zap className="w-8 h-8 text-black" />
                 <ArrowRight className="w-6 h-6 text-black/30 group-hover:text-black -rotate-45 group-hover:rotate-0 transition-all duration-500" />
              </div>
              <div>
                 <h3 className="nike-header text-3xl text-black mb-2">Run<br/>Simulation</h3>
                 <p className="label-mono text-[10px] text-zinc-500">Load Demo Portfolio</p>
              </div>
           </div>
        </div>
      </div>
    );
  }

  if (step === 'analyzing') {
    return (
      <div className="min-h-[50vh] flex flex-col items-center justify-center space-y-6 animate-pulse">
        <Activity className="w-16 h-16 text-brand-volt" />
        <div className="text-center space-y-2">
          <h3 className="nike-header text-3xl text-white">Processing</h3>
          <p className="label-mono text-[10px] text-zinc-500">
            Detecting Fatigue // Applying Kelly Criterion
          </p>
        </div>
      </div>
    );
  }

  if (step === 'dashboard' && data) {
    return (
      <div className="animate-fade-up w-full max-w-[1600px] mx-auto pb-20">

        {/* Header */}
        <div className="flex items-center justify-between border-b border-zinc-800 pb-6 mb-10">
          <div className="flex items-center gap-4">
             <button onClick={() => setStep('input')} className="text-zinc-500 hover:text-white transition-colors group">
                <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
             </button>
             <div>
                <h2 className="nike-header text-3xl text-white">Allocation<span className="text-brand-volt">Engine</span></h2>
                <div className="flex gap-2 mt-1">
                   {data.realtime_notes.slice(0, 2).map((note, i) => (
                     <span key={i} className="text-[9px] font-bold text-black bg-brand-volt px-2 py-0.5 uppercase flex items-center gap-1">
                       <AlertTriangle className="w-3 h-3" /> {note}
                     </span>
                   ))}
                </div>
             </div>
          </div>
        </div>

        {/* 1. AI INSIGHTS GRID */}
