// Helper for rate limit retries
const retryOperation = async <T>(
  operation: () => Promise<T>, 
  maxRetries: number = 3, 
  baseDelay: number = 4000
): Promise<T> => {
  let lastError: any;

  for (let i = 0; i < maxRetries; i++) {
    try {
      return await operation();
    } catch (error: any) {
      lastError = error;

      const isRateLimit = 
        error?.status === 429 || 
        error?.code === 429 ||
        error?.message?.includes('429') || 
        error?.message?.includes('Quota exceeded') ||
        error?.message?.includes('RESOURCE_EXHAUSTED');

      if (!isRateLimit) {
        throw error;
      }

      if (i === maxRetries - 1) break;

      // Extract retry delay from error if available (e.g. "Please retry in 58.63s")
      // We look for patterns like "retry in 58s", "retry in 58.6s", etc.
      let delay = baseDelay * Math.pow(2, i);
      const match = error?.message?.match(/retry in\s*(\d+(\.\d+)?)\s*s/i);

      if (match && match[1]) {
         // Add 2000ms buffer to the server's requested wait time to be safe
         delay = Math.ceil(parseFloat(match[1]) * 1000) + 2000;
      }

      console.warn(`[Gemini API] Rate limit hit. Waiting ${delay}ms before retry ${i + 1}/${maxRetries}...`);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }

  throw lastError;
};

